from itertools import combinations, product

def subsets(n,k):
    return list(combinations(range(n),k))
def min_attained_twice(vals):
    m=min(vals)
    return sum(v==m for v in vals)>=2

def plucker_ok(vals, n, k):
    # vals dict tuple sorted size k -> int or inf
    if k==0 or k==n: return True
    if k==1 or k==n-1:
        # tropical GP for rank 1 has no nontrivial (S size -1)
        return True
    # 3-term GP: S size k-2, four distinct
    for S in combinations(range(n), k-2):
        S=set(S)
        rest=[i for i in range(n) if i not in S]
        for quad in combinations(rest,4):
            i,j,l,m=quad
            terms=[
                vals[tuple(sorted(S|{i,j}))]+vals[tuple(sorted(S|{l,m}))],
                vals[tuple(sorted(S|{i,l}))]+vals[tuple(sorted(S|{j,m}))],
                vals[tuple(sorted(S|{i,m}))]+vals[tuple(sorted(S|{j,l}))]
            ]
            if not min_attained_twice(terms):
                return False
    return True

def nested_incidence_ok(p,q,n,a,b):
    for S in combinations(range(n), a-1):
        S=set(S)
        # T size b+1 with S subset T
        for extra in combinations([i for i in range(n) if i not in S], b+1-len(S)):
            T=set(S)|set(extra)
            terms=[]
            for i in T-S:
                terms.append(p[tuple(sorted(S|{i}))]+q[tuple(sorted(T-{i}))])
            if not min_attained_twice(terms):
                return False
    return True

def full_incidence_ok(p,q,n,a,b,return_bad=False):
    for I in combinations(range(n), a-1):
        I=set(I)
        for J in combinations(range(n), b+1):
            J=set(J)
            diff=J-I
            if len(diff)==0: # impossible? if b+1>a-1
                continue
            terms=[]
            for i in diff:
                terms.append(p[tuple(sorted(I|{i}))]+q[tuple(sorted(J-{i}))])
            if not min_attained_twice(terms):
                if return_bad:
                    return False,(tuple(sorted(I)),tuple(sorted(J)),terms,list(diff))
                return False
    return (True,None) if return_bad else True

def enumerate_valuated(n,k,values=(0,1)):
    subs=subsets(n,k)
    arrs=[]
    for bits in product(values, repeat=len(subs)):
        # normalize min 0
        if min(bits)!=0: continue
        vals=dict(zip(subs,bits))
        if plucker_ok(vals,n,k):
            arrs.append(vals)
    return arrs

